<!doctype html><html lang="ja"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{{ $estimate->title }}</title><style>body{margin:0;background:#edf2f4;color:#14212a;font-family:system-ui,-apple-system,"Noto Sans JP",sans-serif}.wrap{max-width:900px;margin:30px auto;padding:20px}.sheet,.response{background:#fff;padding:34px;border-radius:14px;box-shadow:0 8px 28px #173f501a;margin-bottom:18px}.head{display:flex;justify-content:space-between;gap:20px}.amount{font-size:30px;font-weight:900;color:#17495d}.items{width:100%;border-collapse:collapse;margin-top:24px}.items th,.items td{padding:10px;border-bottom:1px solid #d8e0e4;text-align:left}.money{text-align:right!important}.scope{padding:14px;background:#f1f7f5}.actions{display:flex;gap:10px;flex-wrap:wrap}button{padding:12px 22px;border:0;border-radius:8px;background:#1b5265;color:#fff;font-weight:800}.reject{background:#fff;color:#9b4435;border:1px solid #c88}textarea{width:100%;box-sizing:border-box;padding:12px;margin:10px 0}.done{padding:14px;background:#eaf6ee;color:#26633d;border-radius:8px}@media(max-width:650px){.head{display:grid}.sheet,.response{padding:20px}}</style></head><body><main class="wrap">@if(session('status'))<div class="done">{{ session('status') }}</div>@endif<section class="sheet"><div class="head"><div><div>{{ $estimate->client_snapshot['name'] }} 御中</div><h1>御見積書</h1><strong>{{ $estimate->title }}</strong></div><div><div>{{ $estimate->estimate_number }} / 第{{ $estimate->revision_no }}版</div><div>発行日 {{ $estimate->issued_on->format('Y年n月j日') }}</div><div class="amount">￥{{ number_format($estimate->total) }}</div></div></div><table class="items"><thead><tr><th>内容</th><th>数量</th><th>単価</th><th>金額</th></tr></thead><tbody>@foreach($estimate->items->where('is_scope_only',false) as $item)<tr><td>{{ $item->description }}</td><td>{{ (float)$item->quantity }} {{ $item->unit }}</td><td class="money">￥{{ number_format($item->unit_price) }}</td><td class="money">￥{{ number_format($item->amount) }}</td></tr>@endforeach</tbody></table>@if($estimate->items->where('is_scope_only',true)->isNotEmpty())<div class="scope"><strong>作業範囲・実施内容</strong><ul>@foreach($estimate->items->where('is_scope_only',true) as $item)<li>{{ $item->description }}</li>@endforeach</ul></div>@endif</section><section class="response"><h2>見積内容へのご回答</h2>@if(in_array($estimate->status,['accepted','rejected']))<p class="done">回答済みです。ありがとうございました。</p>@else<form method="POST" action="{{ route('public.estimates.respond',$token) }}">@csrf<textarea name="note" rows="4" placeholder="ご質問・連絡事項があればご記入ください"></textarea><div class="actions"><button name="response" value="accept">この内容で承認する</button><button class="reject" name="response" value="reject">今回は辞退する</button></div></form>@endif</section></main></body></html>
